INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-000', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'The Belgian colonial administration deepened Hutu-Tutsi divisions by:', 'Treating all ethnic groups equally', 'Introducing identity cards and racial classification that institutionalised ethnic categories', 'Abolishing all ethnic distinctions', 'Allowing democratic self-governance', 1, 'See mark scheme for detailed explanation.', 1);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-001', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'The Hutu Revolution (1959--61) resulted in:', 'A multi-ethnic democracy', 'The overthrow of Tutsi monarchy and mass exile of Tutsis', 'Belgian recolonisation', 'A Tutsi-dominated republic', 1, 'See mark scheme for detailed explanation.', 2);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-002', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'Which group constituted the majority of Rwanda''s population?', 'Tutsi', 'Twa', 'Hutu', 'Belgian settlers', 2, 'See mark scheme for detailed explanation.', 3);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-003', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'Identity cards were significant in the genocide because:', 'They proved Rwandan citizenship', 'They were used to identify and target Tutsi victims', 'They were voluntary documents', 'They showed educational qualifications', 1, 'See mark scheme for detailed explanation.', 4);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-004', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'The Interahamwe were:', 'A Tutsi rebel group', 'A Hutu militia trained and armed by the government to carry out killings', 'A United Nations peacekeeping force', 'A Belgian colonial police force', 1, 'See mark scheme for detailed explanation.', 5);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-005', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'The Hutu Ten Commandments (1990) were significant because they:', 'Called for peace between Hutus and Tutsis', 'Portrayed all Tutsis as enemies and called for Hutu separation from them', 'Were part of the Arusha Accords', 'Were published by the United Nations', 1, 'See mark scheme for detailed explanation.', 6);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-006', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'The Akazu were:', 'International mediators', 'An inner circle of Hutu Power extremists believed to have planned the genocide', 'Moderate Hutu politicians', 'Tutsi military leaders', 1, 'See mark scheme for detailed explanation.', 7);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-007', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'RTLM was significant during the genocide because it:', 'Called for peace and reconciliation', 'Broadcast hate propaganda, identified Tutsi targets, and coordinated killings', 'Was a Tutsi-controlled media outlet', 'Was operated by the United Nations', 1, 'See mark scheme for detailed explanation.', 8);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-008', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'Calling Tutsis ''cockroaches'' (Inyenzi) was an example of:', 'Cultural respect', 'Dehumanisation designed to make killing psychologically easier', 'Accurate biological classification', 'A term of endearment', 1, 'See mark scheme for detailed explanation.', 9);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-009', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'The role of media in the Rwandan genocide demonstrates that:', 'Media has no influence on violence', 'Propaganda and media can be powerful tools for inciting and coordinating mass violence', 'Only print media can influence public opinion', 'Radio technology was not available in Rwanda', 1, 'See mark scheme for detailed explanation.', 10);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-010', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'The collapse of coffee prices in the late 1980s contributed to the genocide by:', 'Making Rwanda wealthier', 'Causing economic crisis and social frustration that elites channelled into ethnic hatred', 'Improving relations between Hutus and Tutsis', 'Leading to increased foreign investment', 1, 'See mark scheme for detailed explanation.', 11);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-011', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'The colonial legacy contributed to the genocide primarily through:', 'Providing economic development', 'Institutionalising ethnic divisions that post-colonial governments exploited', 'Promoting multi-ethnic democracy', 'Withdrawing all colonial infrastructure', 1, 'See mark scheme for detailed explanation.', 12);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-012', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'The Arusha Accords (1993) were significant because they:', 'Ended the genocide', 'Proposed power-sharing between the Hutu government and RPF, which Hutu extremists opposed', 'Were rejected by the RPF', 'Were imposed by France', 1, 'See mark scheme for detailed explanation.', 13);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-013', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'The assassination of Habyarimana (6 April 1994) was significant because:', 'It ended the civil war peacefully', 'It served as the immediate trigger for the genocide', 'It was carried out by the United Nations', 'It led to democratic elections', 1, 'See mark scheme for detailed explanation.', 14);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-014', '1. Rwanda: Causes', 'SL/HL', 'P1-CI', 'The RPF invasion of 1990 contributed to the genocide by:', 'Bringing peace to Rwanda', 'Increasing Hutu extremist fear and hatred of Tutsis', 'Establishing a Tutsi government immediately', 'Ending colonial rule', 1, 'See mark scheme for detailed explanation.', 15);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-000', '1. Rwanda: Causes', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the role of ethnic tensions as a cause of the Rwandan genocide.', '• Pre-colonial context: Hutu and Tutsi as social/economic categories; debate over whether they were distinct ethnic groups or class distinction', 1);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-001', '1. Rwanda: Causes', 'SL/HL', 'short_answer', 'P1-CI', 9, 'To what extent was the Rwandan genocide planned in advance?', '• Evidence of planning: creation and arming of Interahamwe, distribution of weapons, Hutu Power propaganda, death list', 2);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-002', '1. Rwanda: Causes', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the role of the media in the Rwandan genocide.', '• RTLM: hate broadcasts, target identification, coordination of killings, coded languag', 3);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-003', '1. Rwanda: Causes', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the importance of economic factors as causes of the Rwandan genocide.', '• Economic crisis: coffee price collapse, SAPs, unemployment, povert', 4);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-004', '1. Rwanda: Causes', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the significance of the Rwandan Civil War (1990--93) and the Arusha Accords as causes of the genocide.', '• Civil War: RPF invasion increased anti-Tutsi sentiment; radicalised Hutu Power movemen', 5);

INSERT OR IGNORE INTO history_checklist_sections (id, title, color, unit, sort_order) VALUES ('hist-p1-ci-cl-2', '2. Rwanda: Genocide, Response & Impact', '#C4A36A', 'P1-CI', 2);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-2', '2. Rwanda: Genocide, Response & Impact', '#C4A36A', 'P1-CI', 2);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-015', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'P1-CI', 'The Rwandan genocide killed approximately:', '10,000 people', '100,000 people', '800,000--1,000,000 people', '5 million people', 2, 'See mark scheme for detailed explanation.', 16);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-016', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'P1-CI', 'The genocide was primarily carried out using:', 'Advanced military weapons', 'Nuclear weapons', 'Machetes, clubs, and improvised weapons with mass participation', 'Air strikes', 2, 'See mark scheme for detailed explanation.', 17);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-017', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'P1-CI', 'The genocide ended primarily because:', 'The UN sent a large peacekeeping force', 'The Interahamwe surrendered voluntarily', 'The RPF military advance captured Kigali in July 1994', 'France invaded Rwanda', 2, 'See mark scheme for detailed explanation.', 18);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-018', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'P1-CI', 'Dallaire''s ''genocide fax'' (January 1994) was significant because:', 'It led to immediate UN intervention', 'It warned of planned genocide but was ignored by UN headquarters', 'It called for the withdrawal of UN forces', 'It was sent after the genocide began', 1, 'See mark scheme for detailed explanation.', 19);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-019', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'P1-CI', 'The UN Security Council reduced UNAMIR forces during the genocide because:', 'The genocide had ended', 'Member states were unwilling to risk troops; the Belgian withdrawal after peacekeepers were killed prompted the reduction', 'Rwanda requested it', 'The RPF controlled the country', 1, 'See mark scheme for detailed explanation.', 20);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-020', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'P1-CI', 'The US avoided using the word ''genocide'' during the crisis because:', 'There was no evidence of genocide occurring', 'Using the term would create a legal obligation under the Genocide Convention to intervene', 'The US supported the Hutu government', 'It was a translation error', 1, 'See mark scheme for detailed explanation.', 21);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-021', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'P1-CI', 'Opération Turquoise was controversial because:', 'It was a successful humanitarian mission with no complications', 'France had previously supported the Habyarimana government, raising questions about its motives', 'It was carried out by the RPF', 'It prevented all civilian casualties', 1, 'See mark scheme for detailed explanation.', 22);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-022', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'P1-CI', 'The Gacaca courts were:', 'International criminal tribunals', 'Community-based courts used to try genocide suspects and promote reconciliation', 'Military courts', 'Colonial-era courts restored by the government', 1, 'See mark scheme for detailed explanation.', 23);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-023', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'P1-CI', 'The ICTR was significant because:', 'It was the first international tribunal to convict a head of government (PM Kambanda) for genocide', 'It tried all genocide suspects in Rwanda', 'It was based in Kigali', 'It was established before the genocide began', 0, 'See mark scheme for detailed explanation.', 24);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-024', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'P1-CI', 'Rwanda''s involvement in the DRC was primarily motivated by:', 'A desire to colonise the DRC', 'The need to dismantle Hutu militia camps in eastern Zaire and ensure security', 'UN requests for intervention', 'Economic cooperation agreements', 1, 'See mark scheme for detailed explanation.', 25);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-025', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'P1-CI', 'The ICC was established partly as a response to:', 'World War I', 'The failures of international justice in Rwanda and Yugoslavia', 'The Cold War', 'European colonial expansion', 1, 'See mark scheme for detailed explanation.', 26);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-005', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Examine the nature of the Rwandan genocide and the crimes against humanity committed.', '• Scale: 800,000--1,000,000 killed in ~100 days; one of the fastest genocides in histor', 6);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-006', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the response of the international community to the Rwandan genocide.', '• UNAMIR: understaffed, restrictive mandate, Dallaire''s warnings ignored, forces reduced during genocid', 7);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-007', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the effectiveness of justice and reconciliation efforts in post-genocide Rwanda.', '• ICTR: convicted senior leaders; established legal precedents; but slow and expensiv', 8);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-008', '2. Rwanda: Genocide, Response & Impact', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the political and economic impact of the genocide on Rwanda and the wider region.', '• Rwanda: RPF government; political stability but authoritarianism; economic developmen', 9);

