INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-026', '3. Kosovo: Causes & Conflict', 'SL/HL', 'P1-CI', 'The 1974 Yugoslav Constitution was significant for Kosovo because it:', 'Abolished Kosovo as a political entity', 'Granted Kosovo significant autonomy within Yugoslavia', 'Made Kosovo an independent state', 'Gave Serbs complete control over Kosovo', 1, 'See mark scheme for detailed explanation.', 27);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-027', '3. Kosovo: Causes & Conflict', 'SL/HL', 'P1-CI', 'The Battle of Kosovo (1389) was important in the context of the 1990s conflict because:', 'It was the immediate cause of the war', 'It was central to Serbian national mythology and used to justify claims to Kosovo', 'Albanian nationalists used it to claim independence', 'It was irrelevant to modern politics', 1, 'See mark scheme for detailed explanation.', 28);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-028', '3. Kosovo: Causes & Conflict', 'SL/HL', 'P1-CI', 'Milosevic revoked Kosovo''s autonomy in 1989 primarily to:', 'Promote Albanian rights', 'Consolidate his power using Serbian nationalism', 'Comply with international demands', 'Implement democratic reforms', 1, 'See mark scheme for detailed explanation.', 29);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-029', '3. Kosovo: Causes & Conflict', 'SL/HL', 'P1-CI', 'Ibrahim Rugova''s strategy was:', 'Armed resistance against Serbia', 'Peaceful, non-violent resistance and creation of parallel Albanian institutions', 'Alliance with Milosevic', 'Emigration of all Kosovar Albanians', 1, 'See mark scheme for detailed explanation.', 30);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-030', '3. Kosovo: Causes & Conflict', 'SL/HL', 'P1-CI', 'After 1989, Kosovar Albanians experienced:', 'Greater autonomy and freedom', 'Dismissal from public sector jobs, closure of Albanian schools, and systematic repression', 'Democratic elections', 'Economic prosperity', 1, 'See mark scheme for detailed explanation.', 31);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-031', '3. Kosovo: Causes & Conflict', 'SL/HL', 'P1-CI', 'The Dayton Accords (1995) affected Kosovo because:', 'They resolved the Kosovo conflict', 'They ignored Kosovo entirely, disillusioning Kosovar Albanians with peaceful methods', 'They granted Kosovo independence', 'They strengthened Rugova''s position', 1, 'See mark scheme for detailed explanation.', 32);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-032', '3. Kosovo: Causes & Conflict', 'SL/HL', 'P1-CI', 'Rugova''s non-violent strategy ultimately lost support among Kosovar Albanians because:', 'It was too violent', 'Years of peaceful resistance failed to gain meaningful international attention or change on the ground', 'Milosevic agreed to all Albanian demands', 'The UN endorsed violence', 1, 'See mark scheme for detailed explanation.', 33);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-033', '3. Kosovo: Causes & Conflict', 'SL/HL', 'P1-CI', 'The KLA gained mass support primarily because:', 'Rugova endorsed armed resistance', 'Serbian disproportionate reprisals against Albanian civilians radicalised the population', 'The UN armed the KLA', 'NATO requested their formation', 1, 'See mark scheme for detailed explanation.', 34);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-034', '3. Kosovo: Causes & Conflict', 'SL/HL', 'P1-CI', 'The Drenica massacres (1998) were significant because they:', 'Ended the conflict', 'Drew international attention to Serbian atrocities against Albanian civilians', 'Were carried out by the KLA', 'Had no international impact', 1, 'See mark scheme for detailed explanation.', 35);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-035', '3. Kosovo: Causes & Conflict', 'SL/HL', 'P1-CI', 'The Račak massacre (1999) was significant because:', 'It ended the Kosovo conflict', 'It was a key catalyst that led to NATO''s decision to intervene militarily', 'It was carried out by the KLA', 'It had no impact on international policy', 1, 'See mark scheme for detailed explanation.', 36);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-036', '3. Kosovo: Causes & Conflict', 'SL/HL', 'P1-CI', 'The Rambouillet negotiations failed because:', 'The Kosovar Albanians refused all terms', 'Serbia refused to accept NATO peacekeepers on its territory', 'NATO refused to participate', 'Both sides agreed immediately', 1, 'See mark scheme for detailed explanation.', 37);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-009', '3. Kosovo: Causes & Conflict', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the causes of ethnic tension between Serbs and Kosovar Albanians.', '• Historical: Battle of Kosovo mythology; Ottoman period; different religious and cultural identitie', 10);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-010', '3. Kosovo: Causes & Conflict', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the role and significance of Slobodan Milosevic in the Kosovo conflict.', '• Rise to power: exploitation of Serbian nationalism; Gazimestan speec', 11);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-011', '3. Kosovo: Causes & Conflict', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the effectiveness of Ibrahim Rugova''s strategy of non-violent resistance in Kosovo.', '• Achievements: maintained Albanian civil society, avoided bloodshed, moral authorit', 12);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-012', '3. Kosovo: Causes & Conflict', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the role of the KLA in the Kosovo conflict.', '• Formation: disillusionment with Rugova''s peaceful approach; Albanian arms crisi', 13);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-013', '3. Kosovo: Causes & Conflict', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the significance of the Račak massacre and Rambouillet negotiations for the Kosovo conflict.', '• Račak: 45 civilians killed; Walker declared it a crime against humanity; shocked international communit', 14);

INSERT OR IGNORE INTO history_checklist_sections (id, title, color, unit, sort_order) VALUES ('hist-p1-ci-cl-4', '4. Kosovo: Response & Impact', '#C4A36A', 'P1-CI', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-4', '4. Kosovo: Response & Impact', '#C4A36A', 'P1-CI', 4);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-037', '4. Kosovo: Response & Impact', 'SL/HL', 'P1-CI', 'NATO''s bombing campaign was controversial because:', 'It was authorised by the UN Security Council', 'It bypassed the UN Security Council, raising questions about its legality under international law', 'Serbia had asked for NATO intervention', 'It lasted only one day', 1, 'See mark scheme for detailed explanation.', 38);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-038', '4. Kosovo: Response & Impact', 'SL/HL', 'P1-CI', 'Resolution 1244 (1999):', 'Recognised Kosovo''s independence', 'Placed Kosovo under UN administration while maintaining nominal Serbian sovereignty', 'Authorised the genocide', 'Was vetoed by Russia', 1, 'See mark scheme for detailed explanation.', 39);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-039', '4. Kosovo: Response & Impact', 'SL/HL', 'P1-CI', 'KFOR''s role in Kosovo was to:', 'Support Serbian military operations', 'Maintain security and supervise Serbian withdrawal from Kosovo', 'Carry out the NATO bombing campaign', 'Administer elections in Serbia', 1, 'See mark scheme for detailed explanation.', 40);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-040', '4. Kosovo: Response & Impact', 'SL/HL', 'P1-CI', 'The Kosovo refugee crisis involved approximately:', '10,000 displaced people', '100,000 displaced people', 'Nearly 1 million displaced Kosovar Albanians', '5 million displaced people', 2, 'See mark scheme for detailed explanation.', 41);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-041', '4. Kosovo: Response & Impact', 'SL/HL', 'P1-CI', 'After the war, Kosovo''s Serbian minority:', 'Remained fully integrated into society', 'Faced revenge attacks and many fled; approximately 200,000 Serbs were displaced', 'Gained political control of Kosovo', 'Were protected by the Serbian army', 1, 'See mark scheme for detailed explanation.', 42);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-042', '4. Kosovo: Response & Impact', 'SL/HL', 'P1-CI', 'Ibrahim Rugova''s election as president in 2002 was significant because:', 'It led to immediate Kosovo independence', 'It represented a democratic transition and return to Rugova''s peaceful approach', 'Serbia endorsed his presidency', 'It ended the UNMIK mission', 1, 'See mark scheme for detailed explanation.', 43);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-043', '4. Kosovo: Response & Impact', 'SL/HL', 'P1-CI', 'The ''standards before status'' policy meant:', 'Kosovo would immediately become independent', 'Kosovo had to meet governance standards before its political status would be determined', 'Serbia would decide Kosovo''s future', 'NATO would permanently govern Kosovo', 1, 'See mark scheme for detailed explanation.', 44);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-044', '4. Kosovo: Response & Impact', 'SL/HL', 'P1-CI', 'Milosevic''s indictment was historically significant because:', 'He was the first person ever charged with a crime', 'He was the first sitting head of state to be indicted for war crimes by an international tribunal', 'He was immediately convicted', 'The charges were dropped', 1, 'See mark scheme for detailed explanation.', 45);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-045', '4. Kosovo: Response & Impact', 'SL/HL', 'P1-CI', 'A key limitation of the ICTY was:', 'It had unlimited funding and time', 'Milosevic died before a verdict was reached, and proceedings were criticised as slow', 'It only prosecuted minor figures', 'It was based in Kosovo', 1, 'See mark scheme for detailed explanation.', 46);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-014', '4. Kosovo: Response & Impact', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the international community''s response to the Kosovo crisis.', '• Diplomatic efforts: Contact Group, Rambouillet negotiations; failed to reach agreemen', 15);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-015', '4. Kosovo: Response & Impact', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Examine the social and economic consequences of the Kosovo conflict.', '• Refugee crisis: ~1 million Albanians displaced; post-war displacement of ~200,000 Serb', 16);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-016', '4. Kosovo: Response & Impact', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the political impact of the Kosovo conflict on the region.', '• Kosovo: transition from UN administration to self-governance; democratic elections; path to independenc', 17);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-017', '4. Kosovo: Response & Impact', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the significance of the ICTY and the indictment of Milosevic for international justice.', '• Precedent: first sitting head of state indicted; demonstrated no one is above international la', 18);

