INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1', '1. Civil Rights: Segregation & Discrimination', '#7B9E6B', 'P1-RP', 1);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-046', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'P1-RP', 'Plessy v. Ferguson (1896) established the principle of:', 'Racial equality under the law', '''Separate but equal'' as constitutional', 'Universal suffrage for all races', 'Federal protection against lynching', 1, 'See mark scheme for detailed explanation.', 47);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-047', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'P1-RP', 'The Emmett Till case (1955) was significant because:', 'It led to the immediate passage of civil rights legislation', 'His open-casket funeral exposed the brutality of racial violence and galvanised the movement', 'His murderers were convicted and jailed', 'It ended KKK violence in the South', 1, 'See mark scheme for detailed explanation.', 48);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-048', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'P1-RP', 'White Citizens'' Councils differed from the KKK primarily in that they:', 'Supported civil rights', 'Used economic pressure and political influence rather than direct violence', 'Were based in the North', 'Were outlawed by the federal government', 1, 'See mark scheme for detailed explanation.', 49);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-049', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'P1-RP', 'Jim Crow laws enforced:', 'Equal rights for all citizens', 'Racial segregation in the American South', 'Northern industrial labour standards', 'Federal civil rights protections', 1, 'See mark scheme for detailed explanation.', 50);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-050', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'P1-RP', 'Literacy tests were used to disenfranchise African Americans by:', 'Testing all voters equally', 'Being selectively and unfairly applied to Black voters', 'Providing free education', 'Encouraging voter registration', 1, 'See mark scheme for detailed explanation.', 51);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-051', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'P1-RP', 'The grandfather clause was designed to:', 'Help African Americans vote', 'Allow illiterate white voters to bypass literacy tests while excluding Black voters', 'Extend voting rights to immigrants', 'Reform the electoral system', 1, 'See mark scheme for detailed explanation.', 52);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-052', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'P1-RP', 'Brown v. Board of Education (1954) was significant because:', 'It upheld Plessy v. Ferguson', 'It ruled that segregated schools were inherently unequal, overturning ''separate but equal''', 'It ended all forms of racial discrimination immediately', 'It was a split decision with limited authority', 1, 'See mark scheme for detailed explanation.', 53);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-053', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'P1-RP', 'Brown II (1955) weakened the impact of Brown I by:', 'Reversing the original decision', 'Ordering desegregation ''with all deliberate speed'', allowing Southern delays', 'Requiring immediate integration of all schools', 'Imposing fines on segregated schools', 1, 'See mark scheme for detailed explanation.', 54);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-054', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'P1-RP', 'The Clark doll tests were used in the Brown case to demonstrate:', 'That African American children were academically superior', 'That segregation damaged the self-esteem and psychological well-being of Black children', 'That white children preferred Black dolls', 'That desegregation would be easy to implement', 1, 'See mark scheme for detailed explanation.', 55);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-055', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'P1-RP', 'Eisenhower sent federal troops to Little Rock to:', 'Support Governor Faubus', 'Enforce the desegregation of Central High School', 'Close the school permanently', 'Arrest the Little Rock Nine', 1, 'See mark scheme for detailed explanation.', 56);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-056', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'P1-RP', 'The Little Rock crisis was significant because:', 'It showed that states could successfully resist federal law', 'It demonstrated federal willingness to enforce desegregation by force', 'It ended school segregation in the South', 'It was widely ignored by the media', 1, 'See mark scheme for detailed explanation.', 57);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-057', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'P1-RP', 'Redlining was a practice that:', 'Provided loans to African Americans at favourable rates', 'Denied financial services to residents of predominantly Black neighbourhoods', 'Integrated housing in Southern cities', 'Was outlawed by the Plessy v. Ferguson decision', 1, 'See mark scheme for detailed explanation.', 58);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-058', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'P1-RP', 'The economic impact of Jim Crow laws included:', 'Equal economic opportunities for all races', 'Systematic exclusion of African Americans from well-paying jobs and financial services', 'Rapid economic development in African American communities', 'Federal wealth redistribution programmes', 1, 'See mark scheme for detailed explanation.', 59);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-018', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Examine the nature and impact of racial discrimination in the United States before the civil rights movement.', '• Legal discrimination: Jim Crow laws, Plessy v. Ferguson, disenfranchisemen', 19);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-019', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the effectiveness of methods used to disenfranchise African Americans in the South.', '• Methods: poll taxes, literacy tests, grandfather clauses, white primaries, intimidatio', 20);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-020', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of Brown v. Board of Education (1954) for the civil rights movement.', '• Legal significance: overturned Plessy v. Ferguson for education; established that segregation was unconstitutiona', 21);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-021', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of the Little Rock crisis (1957) for the civil rights movement.', '• Events: Faubus''s defiance, mob violence, Eisenhower''s deployment of federal troop', 22);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-022', '1. Civil Rights: Segregation & Discrimination', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Examine the nature and impact of economic and social discrimination on African Americans.', '• Economic: lower wages, job exclusion, sharecropping, union discriminatio', 23);

INSERT OR IGNORE INTO history_checklist_sections (id, title, color, unit, sort_order) VALUES ('hist-p1-rp-cl-2', '2. Civil Rights: Protests & Legislation', '#7B9E6B', 'P1-RP', 6);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-2', '2. Civil Rights: Protests & Legislation', '#7B9E6B', 'P1-RP', 2);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-059', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', 'The Montgomery Bus Boycott lasted approximately:', '30 days', '100 days', '381 days', '2 years', 2, 'See mark scheme for detailed explanation.', 60);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-060', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', 'The boycott ended primarily because:', 'Buses voluntarily desegregated', 'The Supreme Court ruled bus segregation unconstitutional (Browder v. Gayle)', 'Martin Luther King was arrested', 'Montgomery voters passed a desegregation law', 1, 'See mark scheme for detailed explanation.', 61);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-061', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', 'Rosa Parks''s act of defiance was significant because:', 'She was the first person to resist bus segregation', 'Her arrest was used strategically by the NAACP to challenge segregation', 'She used violence to resist', 'It had no lasting impact', 1, 'See mark scheme for detailed explanation.', 62);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-062', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', 'Martin Luther King''s role in the boycott established him as:', 'A local Montgomery politician', 'The national leader of non-violent civil rights protest', 'President of the NAACP', 'A Supreme Court justice', 1, 'See mark scheme for detailed explanation.', 63);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-063', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', 'The Freedom Rides were organised primarily to:', 'Register voters in the South', 'Test enforcement of desegregation rulings on interstate bus travel', 'Protest the Vietnam War', 'Support President Kennedy''s election', 1, 'See mark scheme for detailed explanation.', 64);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-064', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', 'The violence against Freedom Riders in Alabama was significant because:', 'It ended the civil rights movement', 'It attracted national media attention and forced federal intervention', 'It showed that segregation was popular nationwide', 'It had no impact on federal policy', 1, 'See mark scheme for detailed explanation.', 65);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-065', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', 'Freedom Summer (1964) was primarily focused on:', 'Desegregating schools', 'Voter registration in Mississippi', 'Boycotting businesses', 'Integrating the military', 1, 'See mark scheme for detailed explanation.', 66);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-066', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', 'The murders of Chaney, Goodman, and Schwerner were significant because:', 'They ended the civil rights movement', 'They attracted national attention and increased support for civil rights legislation', 'They went unreported', 'They were committed by federal agents', 1, 'See mark scheme for detailed explanation.', 67);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-067', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', 'The MFDP challenged the Democratic Party by:', 'Running a Republican candidate', 'Seeking to replace the all-white Mississippi delegation at the national convention', 'Supporting segregationist candidates', 'Withdrawing from politics entirely', 1, 'See mark scheme for detailed explanation.', 68);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-068', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', 'The Civil Rights Act (1964) primarily:', 'Gave African Americans the right to vote', 'Prohibited discrimination based on race in public facilities and employment', 'Ended poverty in African American communities', 'Established affirmative action quotas', 1, 'See mark scheme for detailed explanation.', 69);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-069', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', 'The Birmingham Campaign (1963) was crucial for civil rights legislation because:', 'It was entirely peaceful', 'Media coverage of police brutality shocked the nation and built support for legislation', 'It took place in a Northern city', 'President Kennedy led the protests', 1, 'See mark scheme for detailed explanation.', 70);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-070', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', 'President Johnson was able to pass the Civil Rights Act partly because:', 'He had no political opposition', 'He used Kennedy''s assassination and legacy as political leverage', 'The Act was universally popular', 'The Supreme Court ordered it', 1, 'See mark scheme for detailed explanation.', 71);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-071', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', '''Bloody Sunday'' in Selma (1965) directly contributed to:', 'The end of the Vietnam War', 'National support for the Voting Rights Act', 'The election of an African American president', 'The founding of the Black Panther Party', 1, 'See mark scheme for detailed explanation.', 72);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-072', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'P1-RP', 'The Voting Rights Act (1965) was significant because:', 'It only applied to Northern states', 'It outlawed discriminatory voting practices and enabled federal oversight of registration', 'It had no measurable impact on voter registration', 'It was vetoed by President Johnson', 1, 'See mark scheme for detailed explanation.', 73);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-023', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of the Montgomery Bus Boycott (1955--56) for the civil rights movement.', '• Immediate impact: first major sustained community-wide Black protest in the South; economic pressure on bus compan', 24);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-024', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the effectiveness of the Freedom Rides (1961) in advancing civil rights.', '• Aims: test compliance with desegregation of interstate travel; provoke federal interventio', 25);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-025', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of Freedom Summer (1964) for the civil rights movement.', '• Aims and methods: voter registration, Freedom Schools, community organisin', 26);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-026', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the factors that led to the passage of the Civil Rights Act (1964).', '• Grassroots activism: Birmingham Campaign, March on Washington, years of protest', 27);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-027', '2. Civil Rights: Protests & Legislation', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of the Voting Rights Act (1965) for African Americans.', '• Context: Selma marches, Bloody Sunday, years of voter registration campaign', 28);

INSERT OR IGNORE INTO history_checklist_sections (id, title, color, unit, sort_order) VALUES ('hist-p1-rp-cl-3', '3. Civil Rights: Key Figures & Groups', '#7B9E6B', 'P1-RP', 7);
