INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-073', '3. Civil Rights: Key Figures & Groups', 'SL/HL', 'P1-RP', 'MLK''s philosophy of non-violence was influenced by:', 'Malcolm X and the Nation of Islam', 'Gandhi''s principles of satyagraha and Christian theology', 'Marxist revolutionary theory', 'The Black Panther Party', 1, 'See mark scheme for detailed explanation.', 74);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-074', '3. Civil Rights: Key Figures & Groups', 'SL/HL', 'P1-RP', 'The Letter from Birmingham Jail (1963) argued that:', 'Violence was necessary for change', 'Non-violent direct action was justified and white moderates who prioritised order over justice were part of the problem', 'The civil rights movement should slow down', 'Segregation was acceptable in some circumstances', 1, 'See mark scheme for detailed explanation.', 75);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-075', '3. Civil Rights: Key Figures & Groups', 'SL/HL', 'P1-RP', 'Malcolm X''s views differed from MLK''s primarily in that Malcolm X:', 'Opposed all forms of protest', 'Advocated Black self-defence and empowerment rather than integration through non-violence', 'Supported segregation for all races', 'Rejected any form of religious belief', 1, 'See mark scheme for detailed explanation.', 76);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-076', '3. Civil Rights: Key Figures & Groups', 'SL/HL', 'P1-RP', 'After his pilgrimage to Mecca, Malcolm X:', 'Became more radical and separatist', 'Adopted a more inclusive view of racial justice, moving away from strict separatism', 'Rejoined the Nation of Islam', 'Abandoned political activism entirely', 1, 'See mark scheme for detailed explanation.', 77);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-077', '3. Civil Rights: Key Figures & Groups', 'SL/HL', 'P1-RP', 'Johnson''s primary contribution to civil rights was:', 'Leading protest marches in the South', 'Using political skill to pass landmark civil rights and voting rights legislation', 'Founding the SCLC', 'Arguing Brown v. Board before the Supreme Court', 1, 'See mark scheme for detailed explanation.', 78);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-078', '3. Civil Rights: Key Figures & Groups', 'SL/HL', 'P1-RP', 'The NAACP''s primary strategy was:', 'Armed resistance', 'Legal challenges through the courts', 'Separatism and self-reliance', 'Economic boycotts only', 1, 'See mark scheme for detailed explanation.', 79);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-079', '3. Civil Rights: Key Figures & Groups', 'SL/HL', 'P1-RP', 'SNCC differed from the SCLC primarily in that SNCC was:', 'Opposed to civil rights', 'Student-led and often more willing to take direct action at the grassroots level', 'Only active in Northern cities', 'A legal organisation', 1, 'See mark scheme for detailed explanation.', 80);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-028', '3. Civil Rights: Key Figures & Groups', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the role and significance of Martin Luther King Jr. in the civil rights movement.', '• Leadership: Montgomery, Birmingham, Selma, March on Washington; Nobel Peace Priz', 29);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-029', '3. Civil Rights: Key Figures & Groups', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Compare and contrast the roles of Martin Luther King Jr. and Malcolm X in the civil rights movement.', '• MLK: non-violence, integration, moral persuasion, legal change, Southern focu', 30);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-030', '3. Civil Rights: Key Figures & Groups', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the role of Lyndon B. Johnson in advancing civil rights.', '• Legislative achievements: Civil Rights Act (1964), Voting Rights Act (1965), Great Society programme', 31);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-031', '3. Civil Rights: Key Figures & Groups', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the relative effectiveness of the key civil rights organisations (NAACP, SCLC, SNCC, Nation of Islam).', '• NAACP: legal victories (Brown v. Board); limited in direct actio', 32);

INSERT OR IGNORE INTO history_checklist_sections (id, title, color, unit, sort_order) VALUES ('hist-p1-rp-cl-4', '4. South Africa: Apartheid & Resistance', '#7B9E6B', 'P1-RP', 8);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-4', '4. South Africa: Apartheid & Resistance', '#7B9E6B', 'P1-RP', 4);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-080', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'P1-RP', 'The Population Registration Act (1950) required:', 'All South Africans to register with a political party', 'Classification of all citizens into racial categories', 'Universal suffrage for all races', 'Equal distribution of land', 1, 'See mark scheme for detailed explanation.', 81);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-081', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'P1-RP', '''Grand Apartheid'' refers to:', 'Segregation of public facilities', 'Large-scale structural segregation including the homeland/Bantustan system', 'International sanctions against South Africa', 'The anti-apartheid movement', 1, 'See mark scheme for detailed explanation.', 82);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-082', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'P1-RP', 'The Group Areas Act (1950):', 'Allowed all races to live anywhere', 'Designated specific residential areas for each racial group', 'Created employment equality', 'Was voluntary for all citizens', 1, 'See mark scheme for detailed explanation.', 83);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-083', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'P1-RP', 'The purpose of the Bantustan system was to:', 'Create independent, prosperous Black states', 'Strip Black South Africans of citizenship and deny them political rights in South Africa', 'Integrate all races within South Africa', 'Provide quality education to all citizens', 1, 'See mark scheme for detailed explanation.', 84);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-084', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'P1-RP', 'The Bantu Education Act (1953) was designed to:', 'Provide equal education for all races', 'Prepare Black South Africans only for manual labour and low-skilled work', 'Train future Black political leaders', 'Integrate schools across racial lines', 1, 'See mark scheme for detailed explanation.', 85);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-085', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'P1-RP', 'The Defiance Campaign (1952) was significant because:', 'It overthrew the apartheid government', 'It was the first major mass civil disobedience campaign against apartheid and dramatically increased ANC membership', 'It was entirely unsuccessful', 'It was organised by the government', 1, 'See mark scheme for detailed explanation.', 86);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-086', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'P1-RP', 'The Freedom Charter (1955) called for:', 'Continued white minority rule', 'A non-racial, democratic South Africa where the country belongs to all who live in it', 'Armed revolution and communist government', 'Separation of all racial groups into independent states', 1, 'See mark scheme for detailed explanation.', 87);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-087', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'P1-RP', 'The Sharpeville Massacre (1960) was a turning point because:', 'It ended apartheid immediately', 'It led to the banning of the ANC and PAC and the adoption of armed struggle', 'It strengthened international support for the apartheid government', 'It was a minor incident with little impact', 1, 'See mark scheme for detailed explanation.', 88);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-088', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'P1-RP', 'Umkhonto we Sizwe (MK) was:', 'A peaceful protest organisation', 'The armed wing of the ANC, founded after non-violent methods were deemed insufficient', 'A government security force', 'A trade union', 1, 'See mark scheme for detailed explanation.', 89);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-089', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'P1-RP', 'The Rivonia Trial (1963--64) resulted in:', 'The acquittal of all defendants', 'Life imprisonment for Mandela and other MK leaders', 'The end of apartheid', 'International recognition of the South African government', 1, 'See mark scheme for detailed explanation.', 90);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-090', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'P1-RP', 'Mandela''s speech from the dock was significant because:', 'He pleaded guilty to all charges', 'He articulated his commitment to democracy and willingness to die for freedom, making him an international symbol', 'He denounced the ANC', 'It was never published', 1, 'See mark scheme for detailed explanation.', 91);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-091', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'P1-RP', 'Albert Luthuli is significant because he:', 'Founded the PAC', 'Led the ANC and was the first African to receive the Nobel Peace Prize', 'Organised the Soweto uprising', 'Was the first president of democratic South Africa', 1, 'See mark scheme for detailed explanation.', 92);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-092', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'P1-RP', 'Robert Sobukwe differed from ANC leaders primarily in his:', 'Support for apartheid', 'More Africanist ideology and rejection of multi-racial alliances', 'Opposition to all forms of protest', 'Support for white minority rule', 1, 'See mark scheme for detailed explanation.', 93);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-032', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Examine the nature of apartheid legislation in South Africa after 1948.', '• Petty Apartheid: everyday segregation of public facilities, social interactio', 33);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-033', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the impact of the apartheid classification system on Black South Africans.', '• Population Registration Act: racial classification determined every aspect of lif', 34);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-034', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the effectiveness of non-violent resistance against apartheid in South Africa up to 1960.', '• Campaigns: Defiance Campaign, Freedom Charter, Women''s March, bus boycott', 35);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-035', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of the Sharpeville Massacre (1960) for the anti-apartheid movement.', '• Events: PAC anti-pass protest, police opened fire, 69 kille', 36);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-036', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of Nelson Mandela for the anti-apartheid movement up to 1964.', '• Early activism: ANC Youth League, Defiance Campaign, Freedom Charte', 37);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-037', '4. South Africa: Apartheid & Resistance', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the role and significance of any two key individuals in the anti-apartheid movement.', '• Choose two: Mandela, Luthuli, Sobukwe, Tutu, Tamb', 38);

