INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-099', '1. Japan: Nationalism & Expansion', 'SL/HL', 'P1-MGW', 'The Zaibatsu were:', 'Military officer factions within the Japanese army', 'Powerful industrial and financial conglomerates', 'Political parties supporting democratic reform', 'Secret societies promoting assassination', 1, 'See mark scheme for detailed explanation.', 100);
