INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can explain the origins of Hutu-Tutsi ethnic tensions in Rwanda.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can describe how colonial rule (Belgian) institutionalised and deepened ethnic divisions.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can analyse the significance of the Hutu Revolution (1959--61).', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can discuss the role of identity cards in the genocide.', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can evaluate the extent to which ethnicity was a colonial construct vs. pre-colonial reality.', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can describe the Hutu Power ideology and its key features.', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can explain the formation and role of the Interahamwe militia.', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can analyse the significance of the Hutu Ten Commandments.', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can discuss the role of the Akazu in planning the genocide.', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can evaluate the extent to which the genocide was planned in advance.', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can describe the role of RTLM and Kangura in promoting genocide.', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can explain how media dehumanised Tutsis and incited violence.', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can analyse the significance of media as a tool of genocide.', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can evaluate whether the genocide could have occurred without media incitement.', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can explain the economic factors that contributed to the genocide.', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can describe the impact of coffee price collapse and SAPs on Rwandan society.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can analyse the role of the colonial legacy in creating conditions for genocide.', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can discuss population pressure as a contributing factor.', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can evaluate the relative importance of economic vs. ethnic causes.', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can describe the RPF invasion and the Rwandan Civil War (1990--93).', 20);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can explain the Arusha Accords and why they were opposed by extremists.', 21);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can analyse the assassination of Habyarimana as the trigger for the genocide.', 22);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can evaluate whether the genocide was inevitable or could have been prevented.', 23);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-1', 'I can discuss who was responsible for shooting down the plane (contested).', 24);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', 'Hutu', 'Majority ethnic group in Rwanda (~85%); historically farmers; held power from 1962 independence until 1994 genocide.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', 'Tutsi', 'Minority ethnic group (~14%); historically associated with cattle-keeping and pre-colonial aristocracy; targeted in the 1994 genocide.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', 'Twa', 'Smallest ethnic group (~1%); indigenous forest-dwelling people; often marginalised in Rwandan politics. Colonial manipulation of Belgian colonisers institutionalised ethnicity Hutu-Tutsi divisions through identity cards (1933), racial classification, and preferential treatment of Tutsis, then later switched to supporting Hutus.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', 'Hutu Revolution (1959--61)', 'Hutu uprising against Tutsi monarchy; thousands of Tutsis killed or exiled; established Hutu-dominated republic.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', 'Identity cards', 'Introduced by Belgians in 1933; classified all Rwandans as Hutu, Tutsi, or Twa; used during the genocide to identify victims. ☑', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', 'Hutu Power', 'Extremist political ideology promoting Hutu supremacy; sought the elimination of Tutsi ''threat''; key driver of the genocide. Interahamwe (''Those who Hutu militia group, youth wing of the attack together'') MRND party; trained and armed by the government; primary perpetrators of the genocide. Impuzamugambi (''Those who Militia linked to the Coalition for the have the same goal'') Defence of the Republic (CDR); another key perpetrator group in the genocide. Hutu Ten Commandments Published in Kangura newspaper; (1990) portrayed all Tutsis as enemies; called for Hutu vigilance and separation from Tutsis. MRND (National Revolutionary President Habyarimana''s ruling party; Movement for Development) created the Interahamwe militias and promoted Hutu Power ideology.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', 'Akazu (''Little House'')', 'Inner circle of Hutu Power extremists around Habyarimana and his wife; believed to have planned and orchestrated the genocide. ☑', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', 'Kangura newspaper', 'Hutu Power newspaper that published the Hutu Ten Commandments and virulent anti-Tutsi propaganda.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', '''Cut down the tall trees''', 'RTLM coded language instructing Hutus to kill Tutsis; ''tall trees'' was a reference to Tutsis, who were stereotypically portrayed as taller.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', '''Cockroaches'' (Inyenzi)', 'Dehumanising term used by Hutu Power media to describe Tutsis; dehumanisation was a key step toward genocide.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', 'Propaganda techniques', 'Dehumanisation, fear-mongering, conspiracy theories about Tutsi plots, glorification of Hutu identity, calls to ''self-defence''. ☑', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', 'Population pressure', 'Rwanda was one of Africa''s most densely populated countries; competition for land intensified ethnic tensions.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', 'Colonial legacy', 'Belgian divide-and-rule policies created the framework of ethnic hatred; post-colonial Hutu governments continued ethnic discrimination against Tutsis. Habyarimana regime One-party Hutu-dominated state; (1973--94) increasing corruption, economic decline, and resistance to power-sharing fuelled extremism. ☑', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', 'RPF invasion (October 1990)', 'RPF attack from Uganda; triggered increased repression of Tutsis inside Rwanda and radicalisation of Hutu Power. Arusha Accords (August Peace agreement between Habyarimana 1993) government and RPF; provided for power-sharing and integration of RPF into the army; opposed by Hutu extremists. Assassination of Habyarimana President''s plane shot down over (6 April 1994) Kigali airport; also killed Burundian President Ntaryamira; served as the trigger for the genocide.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1', 'Trigger of the genocide', 'Within hours of Habyarimana''s assassination, roadblocks were set up and systematic killing of Tutsis and moderate Hutus began. ☑', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can describe the nature and scale of the Rwandan genocide.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can explain the methods used by the perpetrators.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can discuss the systematic use of sexual violence as a weapon.', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can analyse the role of the RPF in ending the genocide.', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can evaluate the targeting of moderate Hutus alongside Tutsis.', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can describe UNAMIR''s mandate and limitations.', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can explain the significance of Dallaire''s genocide fax.', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can analyse the reasons for international inaction during the genocide.', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can discuss the roles of the US, Belgium, and France.', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can evaluate whether international intervention could have prevented or reduced the genocide.', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can describe the refugee crisis and its regional consequences.', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can explain the Gacaca court system and its strengths and weaknesses.', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can analyse the work of the ICTR.', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can discuss the social impact of the genocide on Rwandan society.', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can evaluate the effectiveness of post-genocide reconciliation efforts.', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can describe the political situation in Rwanda after the genocide.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can explain Rwanda''s involvement in the DRC conflicts.', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can analyse the RPF government''s achievements and criticisms.', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can discuss the establishment of the ICC and Rwanda''s role in its creation.', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-2', 'I can evaluate the long-term consequences of the genocide for the region.', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'Speed of the genocide', 'Approximately 800,000--1,000,000 Tutsis and moderate Hutus killed in approximately 100 days (April--July 1994).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'Methods of killing', 'Primarily machetes, clubs, and other improvised weapons; mass killings at churches, schools, and roadblocks; neighbours killed neighbours.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'War rape', 'Systematic sexual violence against Tutsi women as a weapon of genocide; estimated 250,000--500,000 women raped.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'Moderate Hutus targeted', 'Hutus who opposed the genocide or sheltered Tutsis were also killed; PM Agathe Uwilingiyimana assassinated on 7 April.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'RPF advance', 'RPF forces fought their way from the northeast; gradually took control of Rwanda; ended the genocide by capturing Kigali in July 1994.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'Paul Kagame', 'RPF military commander; led the forces that ended the genocide; became president of Rwanda (2000--present). ☑', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'General Roméo Dallaire', 'Canadian commander of UNAMIR; warned of genocide in January 1994 ''genocide fax'' but was denied permission to act.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'Genocide fax (January 1994)', 'Dallaire''s warning to UN headquarters about weapons caches and planned extermination of Tutsis; UN refused to authorise action.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'US reluctance', 'After Somalia debacle (1993), the US avoided involvement; Clinton administration refused to use the word ''genocide'' to avoid legal obligation to intervene.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'Belgian withdrawal', 'After 10 Belgian peacekeepers were murdered on 7 April, Belgium withdrew its forces from UNAMIR, fatally weakening the mission. Opération Turquoise French military intervention; (June--August 1994) ostensibly humanitarian but controversial; France had previously supported the Habyarimana government. Security Council Resolution Reduced UNAMIR from 2,500 to 270 troops 912 at the height of the genocide (21 April 1994). ☑', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'Refugee crisis (1994)', 'Over 2 million Hutus (including génocidaires) fled to neighbouring countries, especially eastern Zaire (DRC); refugee camps became bases for militants.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'Gacaca courts', 'Community-based justice system used to try hundreds of thousands of genocide suspects; aimed to combine justice with reconciliation. International Criminal UN tribunal established in Arusha, Tribunal for Rwanda (ICTR) Tanzania (1994); tried senior leaders for genocide; convicted key figures including PM Jean Kambanda.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'Social trauma', 'Hundreds of thousands of orphans, widows, survivors of sexual violence; destroyed social fabric; long-term psychological impact.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'Reconciliation efforts', 'Government promoted national unity; removed ethnic identity from ID cards; emphasised ''Rwandan'' identity over ethnic labels. ☑', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'RPF government', 'Paul Kagame''s RPF-led government has ruled Rwanda since 1994; credited with stability and economic growth but criticised for authoritarianism.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2', 'First Congo War (1996--97)', 'Rwanda (and Uganda) invaded Zaire to dismantle Hutu militia camps and overthrow Mobutu; installed Laurent-Désiré Kabila as president. Second Congo War Rwandan forces intervened again in DRC; (1998--2003) deadliest conflict since WWII; estimated 5.4 million excess deaths. Rwandan economic Post-genocide Rwanda achieved development significant economic growth, poverty reduction, and development under Kagame; but at the cost of political freedom. International Criminal Court Established by the Rome Statute (1998); (ICC) permanent court to prosecute genocide, war crimes, and crimes against humanity; inspired partly by Rwanda and Yugoslavia. ☑', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can describe the ethnic composition of Kosovo and the nature of tensions.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can explain the historical significance of Kosovo for Serbian identity.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can analyse the 1974 Constitution and its impact on Kosovo''s autonomy.', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can discuss the rise of Albanian nationalism in Kosovo.', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can evaluate the extent to which ethnic tensions were driven by historical or political factors.', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can explain Milosevic''s revocation of Kosovo''s autonomy and its consequences.', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can describe the repression of Kosovar Albanians after 1989.', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can analyse Rugova''s strategy of non-violent resistance.', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can discuss the parallel institutions created by Kosovar Albanians.', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can evaluate whether peaceful resistance was effective in Kosovo.', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can describe Rugova''s philosophy and strategy of non-violent resistance.', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can explain the shadow republic and parallel institutions.', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can analyse why non-violent resistance ultimately failed to resolve the Kosovo issue.', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can discuss the impact of the Dayton Accords on Kosovar Albanian strategy.', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can evaluate the significance of Rugova compared to the KLA approach.', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can describe the formation and growth of the KLA.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can explain the KLA''s methods and how they differed from Rugova''s approach.', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can analyse the Serbian government''s response to the KLA insurgency.', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can discuss the Drenica massacres and their significance.', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can evaluate the cycle of violence between the KLA and Serbian forces.', 20);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can describe the nature of ethnic cleansing in Kosovo.', 21);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can explain the significance of the Račak massacre.', 22);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can analyse the Rambouillet negotiations and their failure.', 23);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can discuss the escalation of ethnic cleansing during the NATO bombing campaign.', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-3', 'I can evaluate the international response to crimes against humanity in Kosovo.', 25);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Kosovo', 'Province of Serbia; approximately 90% ethnic Albanian population; considered sacred by Serbs due to the 1389 Battle of Kosovo.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Battle of Kosovo (1389)', 'Medieval battle between Serbs and Ottomans; foundation of Serbian national mythology; used to justify Serbian claims to Kosovo.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Kosovar Albanians', 'Ethnic Albanian majority population of Kosovo; predominantly Muslim; sought autonomy or independence from Serbia.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', '1974 Yugoslav Constitution', 'Granted Kosovo significant autonomy within Yugoslavia; had its own government, assembly, and representation in federal institutions.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Rising Albanian nationalism', 'Growing demands for Kosovo to become a full republic within Yugoslavia, not just an autonomous province of Serbia.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Serbian minority in Kosovo', '~10% of Kosovo''s population; viewed with increasing resentment by some Kosovar Albanians; their perceived mistreatment was exploited by Serb nationalists. ☑', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Slobodan Milosevic', 'Serbian and Yugoslav president; revoked Kosovo''s autonomy in 1989; used Serbian nationalism to consolidate power; indicted for war crimes. Revocation of Kosovo''s Milosevic stripped Kosovo of its autonomy (1989) autonomous status; imposed direct Serbian rule; Albanian language and institutions suppressed. Milosevic''s Gazimestan Speech at the 600th anniversary of the speech (1989) Battle of Kosovo; widely interpreted as promoting Serbian nationalism and warning of future conflicts. Apartheid-like system in After 1989: Albanians dismissed from Kosovo public sector jobs, Albanian-language schools and university closed, health care restricted.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Ibrahim Rugova', 'Leader of the Democratic League of Kosovo (LDK); advocated peaceful, non-violent resistance to Serbian rule; ''Gandhi of the Balkans''.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Parallel institutions', 'Kosovar Albanians created shadow government, schools, and healthcare system to operate independently of Serbian state. ☑', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Ibrahim Rugova (1944--2006)', 'Leader of the LDK; declared Kosovo independent in 1991 (unrecognised); elected president of shadow republic; advocated exclusively peaceful methods. Democratic League of Kosovo Major Kosovar Albanian political party; (LDK) led non-violent resistance movement under Rugova.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Shadow Republic of Kosovo', 'Parallel state structures including schools, healthcare, taxation; maintained Albanian civil society under Serbian repression.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Dayton Accords (1995)', 'Peace agreement ending the Bosnian War; Kosovo was not addressed, leading to Kosovar Albanian disillusionment with peaceful methods. Failure of non-violence to Despite years of peaceful resistance, gain international support the international community largely ignored Kosovo''s situation; contributed to the rise of the KLA. ☑', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'KLA tactics', 'Guerrilla warfare, attacks on Serbian police and officials; initially small but gained mass support after Serbian reprisals against civilians.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Serbian counter-insurgency', 'Disproportionate Serbian military and police operations against Albanian civilians; destroyed villages; created massive displacement.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Drenica massacres (1998)', 'Serbian security forces killed dozens of Albanian civilians in the Drenica region; galvanised international attention.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Albanian arms crisis (1997)', 'Collapse of pyramid schemes in Albania led to chaos and looting of military arsenals; weapons flowed to the KLA. ☑', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Ethnic cleansing in Kosovo', 'Systematic Serbian campaign to expel Kosovar Albanians; destruction of villages, mass displacement, killings, sexual violence. Račak massacre (15 January Serbian security forces killed 45 1999) Albanian civilians in the village of Račak; became a key catalyst for NATO intervention.', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'William Walker', 'US diplomat and OSCE verification mission head who declared Račak a ''crime against humanity''; galvanised international response. Rambouillet negotiations Failed peace talks; Serbia refused to (Feb--March 1999) accept NATO peacekeepers in Kosovo; provided the political justification for NATO bombing.', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-3', 'Operation Horseshoe', 'Alleged Serbian plan for the systematic expulsion of Kosovar Albanians; scale of ethnic cleansing accelerated after NATO bombing began. ☑', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can describe the NATO bombing campaign and its justification.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can explain the controversy over NATO''s bypassing of the UN Security Council.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can analyse the effectiveness of the bombing campaign.', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can discuss the role of KFOR and UNMIK in post-war Kosovo.', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can evaluate the legality and morality of NATO''s intervention.', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can describe the scale of the refugee crisis and displacement.', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can explain the social and economic consequences of the conflict.', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can analyse the impact on infrastructure and economic development.', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can discuss the post-war displacement of Kosovo Serbs.', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can evaluate the long-term social consequences of the conflict.', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can describe the political transition in post-war Kosovo.', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can explain the significance of Rugova''s election as president in 2002.', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can analyse the ''standards before status'' policy.', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can discuss the unresolved question of Kosovo''s political status.', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can evaluate the effectiveness of UNMIK governance.', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can describe the ICTY and its purpose.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can explain the significance of Milosevic''s indictment.', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can analyse the impact of the ICTY on international justice.', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can discuss the fall of Milosevic and his trial.', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-ci-cl-4', 'I can evaluate the strengths and limitations of international tribunals.', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-4', 'KFOR (Kosovo Force)', 'NATO-led peacekeeping force deployed to Kosovo after the war; maintained security and supervised Serbian withdrawal. UN Security Council Ended the conflict; placed Kosovo under Resolution 1244 (June 1999) UN administration (UNMIK); authorised KFOR deployment; maintained Serbian sovereignty in theory.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-4', 'UNMIK', 'United Nations Interim Administration Mission in Kosovo; governed Kosovo from 1999 until Kosovo''s independence declaration in 2008. ☑', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-4', 'Kosovo refugee crisis', 'Nearly 1 million Kosovar Albanians displaced during the conflict; mostly to Albania, Macedonia, and Montenegro.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-4', 'Return of refugees', 'After NATO intervention, most Albanian refugees returned; but approximately 200,000 Serbs and Roma fled Kosovo.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-4', 'Infrastructure destruction', 'Extensive damage to homes, schools, hospitals, and infrastructure from both Serbian forces and NATO bombing.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-4', 'Economic devastation', 'Kosovo''s already weak economy further damaged; high unemployment; dependence on international aid.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-4', 'Reverse ethnic cleansing', 'After the war, Kosovar Albanians attacked remaining Serbian communities; destruction of Serbian churches and cultural sites. ☑', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-4', 'UNMIK governance', 'UN administration governed Kosovo from 1999; gradually transferred power to local institutions.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-4', 'Kosovo elections (2001--02)', 'First democratic elections under UNMIK; Ibrahim Rugova elected president of Kosovo in 2002. Rugova as president Led Kosovo through early years of (2002--06) self-governance; continued to advocate for independence through peaceful means.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-4', 'Kosovo''s status question', 'Contested: Kosovar Albanians sought full independence; Serbia insisted Kosovo remained its province; resolved by unilateral declaration in 2008. Standards before status International community required Kosovo policy to meet governance standards before its final political status would be determined. ☑', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-4', 'Milosevic trial', 'Began in 2002; Milosevic defended himself; died in custody in 2006 before a verdict was reached. Fall of Milosevic (October Popular uprising (Bulldozer Revolution) 2000) overthrew Milosevic; he was later extradited to The Hague. Significance of ICTY for Established precedents for prosecuting international justice heads of state; demonstrated accountability for war crimes; but also criticised for being slow and selective. ☑', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can describe the nature and impact of Jim Crow laws on African Americans.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can explain the role of the KKK in maintaining racial terror.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can discuss the significance of the Emmett Till case for the civil rights movement.', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can analyse the legal basis for segregation (Plessy v. Ferguson).', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can evaluate the impact of racial violence on African American communities.', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can describe the various methods used to disenfranchise African Americans.', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can explain how poll taxes, literacy tests, and grandfather clauses worked together.', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can analyse the gap between the 15th Amendment and the reality of voting rights.', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can evaluate the impact of disenfranchisement on African American political power.', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can explain the significance of Brown v. Board of Education.', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can describe the role of Thurgood Marshall and the NAACP legal strategy.', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can analyse the limitations of the Brown decisions (especially Brown II).', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can discuss the concept of ''Massive Resistance'' and Southern opposition.', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can evaluate the immediate and long-term impact of Brown on desegregation.', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can describe the events of the Little Rock crisis.', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can explain the significance of federal intervention.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can analyse the role of media coverage in shaping public opinion.', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can evaluate Little Rock as a turning point in the civil rights movement.', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can describe the economic dimensions of racial discrimination.', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can explain housing discrimination and its long-term effects.', 20);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can analyse the legacy of Jim Crow on African American economic opportunities.', 21);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-1', 'I can evaluate the relationship between economic and social discrimination.', 22);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Jim Crow Laws', 'State and local laws enforcing racial segregation in the American South from the 1870s through the 1960s.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Ku Klux Klan (KKK)', 'White supremacist organisation using violence, intimidation, and lynching to enforce racial hierarchy and terrorise African Americans.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Lynching', 'Extrajudicial murder, often by hanging, of African Americans; used as a tool of racial terror; over 4,000 recorded between 1877 and 1950.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Emmett Till (1955)', '14-year-old African American murdered in Mississippi for allegedly whistling at a white woman; his open-casket funeral galvanised the civil rights movement.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Plessy v. Ferguson (1896)', 'Supreme Court ruling that ''separate but equal'' facilities were constitutional; legal basis for Jim Crow segregation.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'White Citizens'' Councils', 'Middle-class white organisations formed after Brown v. Board to resist desegregation through economic pressure and political influence. ☑', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Poll taxes', 'Fees required to vote; disproportionately excluded poor African Americans from electoral participation.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Literacy tests', 'Tests administered at voter registration; selectively applied to prevent African Americans from voting.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Grandfather clause', 'Exempted those whose ancestors could vote before 1867 from literacy tests; effectively allowed white illiterate voters while excluding Black voters.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', '15th Amendment (1870)', 'Prohibited denying the vote based on race; systematically undermined in the South through legal and extralegal means.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'White primary', 'Practice of excluding African Americans from Democratic Party primaries in the one-party South, effectively denying them any political voice. ☑', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Chief Justice Earl Warren', 'Led the unanimous Brown decision; argued segregation generated feelings of inferiority in African American children.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Brown II (1955)', 'Follow-up ruling ordering desegregation ''with all deliberate speed''; vague wording allowed Southern states to delay.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Thurgood Marshall', 'NAACP lawyer who argued Brown v. Board before the Supreme Court; later became the first African American Supreme Court Justice. Kenneth and Mamie Clark doll Psychological experiments showing Black tests children preferred white dolls; used as evidence in Brown that segregation damaged self-esteem.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Massive Resistance', 'Southern political strategy of defying school desegregation through legal manoeuvres, school closures, and political pressure. ☑', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Little Rock Nine', 'Nine African American students who integrated Central High School in Little Rock, Arkansas, in 1957.', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Governor Orval Faubus', 'Arkansas governor who used the National Guard to prevent the Little Rock Nine from entering Central High School. President Eisenhower''s Sent 1,200 federal troops (101st intervention Airborne) to Little Rock to enforce desegregation; first use of federal troops for civil rights since Reconstruction.', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Elizabeth Eckford', 'One of the Little Rock Nine; photographed being harassed by a white mob while walking to school alone. ☑', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Economic inequality', 'African Americans earned significantly less than white Americans; excluded from many professions and unions.', 19);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Housing discrimination', 'Restrictive covenants, redlining, and discriminatory lending practices confined African Americans to segregated, often impoverished neighbourhoods.', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Redlining', 'Practice of denying financial services to residents of predominantly Black neighbourhoods; institutionalised housing segregation.', 21);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1', 'Sharecropping', 'Post-slavery agricultural system that kept many Southern African Americans in poverty and economic dependence on white landowners. ☑', 22);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can describe the events of the Montgomery Bus Boycott.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can explain the roles of Rosa Parks, MLK, and E.D. Nixon.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can analyse the significance of the boycott for the civil rights movement.', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can evaluate whether the boycott was a success or had limitations.', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can discuss the role of non-violent philosophy in the boycott.', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can describe the purpose and course of the Freedom Rides.', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can explain the violence faced by Freedom Riders and its significance.', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can analyse the role of the federal government in responding to the Rides.', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can evaluate the effectiveness of the Freedom Rides.', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can describe the aims and activities of Freedom Summer.', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can explain the significance of the murders of Chaney, Goodman, and Schwerner.', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can analyse the role of the MFDP at the 1964 Democratic Convention.', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can evaluate the successes and limitations of Freedom Summer.', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can describe the key provisions of the Civil Rights Act (1964).', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can explain how the Birmingham Campaign contributed to the Act.', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can analyse the roles of Kennedy and Johnson in passing the legislation.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can evaluate the significance of the March on Washington.', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can assess the impact and limitations of the Civil Rights Act.', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can describe the Selma to Montgomery marches and Bloody Sunday.', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can explain the key provisions of the Voting Rights Act (1965).', 20);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can analyse the impact of the Act on African American voter registration.', 21);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2', 'I can evaluate the Voting Rights Act as the culmination of the civil rights movement.', 22);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2', 'Rosa Parks (1 Dec 1955)', 'NAACP member who refused to give up her bus seat in Montgomery, Alabama; her arrest sparked the bus boycott. Montgomery Bus Boycott 381-day boycott of Montgomery buses by (1955--56) African Americans; ended when the Supreme Court ruled bus segregation unconstitutional.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2', 'Martin Luther King Jr.', 'Baptist minister who emerged as leader of the boycott; adopted Gandhian philosophy of non-violent resistance. Montgomery Improvement Organisation formed to coordinate the Association (MIA) bus boycott; led by MLK.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2', 'Browder v. Gayle (1956)', 'Federal court ruling (upheld by Supreme Court) that bus segregation was unconstitutional; ended the boycott.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2', 'E.D. Nixon', 'NAACP leader and labour organiser who helped plan the boycott and selected Rosa Parks''s case as a test case. ☑', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2', 'Freedom Rides (May 1961)', 'Interracial groups rode interstate buses through the South to test compliance with desegregation rulings; met with extreme violence. Congress of Racial Equality Civil rights organisation that (CORE) organised the Freedom Rides. Anniston and Birmingham Freedom Riders'' bus was firebombed in attacks Anniston, Alabama; riders were brutally beaten in Birmingham with police complicity. Robert Kennedy''s Attorney General who pressured the ICC intervention to enforce desegregation of interstate bus terminals after the Freedom Rides. Interstate Commerce Banned segregation in interstate bus Commission ruling (1961) terminals; direct result of the Freedom Rides. ☑', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2', 'Freedom Summer (1964)', 'Voter registration campaign in Mississippi; brought hundreds of Northern volunteers to the Deep South. Mississippi murders (June Three civil rights workers (Chaney, 1964) Goodman, Schwerner) were murdered by KKK members with police complicity. Mississippi Freedom Alternative political party created to Democratic Party (MFDP) challenge the all-white Mississippi Democratic delegation at the 1964 convention.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2', 'Fannie Lou Hamer', 'MFDP leader who testified powerfully about voter intimidation at the Democratic National Convention.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2', 'Freedom Schools', 'Alternative schools established during Freedom Summer to educate and empower African American communities. ☑', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2', 'Civil Rights Act (1964)', 'Landmark legislation prohibiting discrimination based on race, colour, religion, sex, or national origin; banned segregation in public facilities.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2', 'Birmingham Campaign (1963)', 'SCLC-led protests in Birmingham, Alabama; images of police brutality (fire hoses, dogs) shocked the nation and built support for legislation. March on Washington (Aug Massive demonstration of 250,000 1963) people; MLK delivered ''I Have a Dream'' speech; pressured Congress to pass civil rights legislation. President Kennedy''s civil Proposed in June 1963 after Birmingham; rights bill became the basis for the 1964 Civil Rights Act after Kennedy''s assassination. President Johnson and the LBJ used political skill and Kennedy''s Civil Rights Act legacy to push the Civil Rights Act through Congress, including breaking a Senate filibuster. ☑', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2', 'Voting Rights Act (1965)', 'Outlawed discriminatory voting practices (literacy tests, poll taxes); authorised federal oversight of voter registration in the South. Selma to Montgomery marches Three protest marches for voting (1965) rights; ''Bloody Sunday'' on the Edmund Pettus Bridge generated national outrage. Bloody Sunday (7 March Alabama state troopers attacked 1965) peaceful marchers with tear gas and clubs on the Edmund Pettus Bridge in Selma.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2', '24th Amendment (1964)', 'Abolished poll taxes in federal elections. Impact of the Voting Rights Black voter registration in Mississippi Act rose from 6.7% in 1964 to 59.8% by 1968; transformed Southern politics. ☑', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can describe MLK''s philosophy of non-violent resistance and its influences.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can explain MLK''s role in key campaigns (Montgomery, Birmingham, Selma, March on Washington).', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can analyse the significance of the Letter from Birmingham Jail.', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can evaluate MLK''s overall contribution to the civil rights movement.', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can describe Malcolm X''s key beliefs and how they evolved over time.', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can explain the differences between Malcolm X''s and MLK''s approaches.', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can analyse Malcolm X''s significance for the Black Power movement.', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can evaluate the impact of Malcolm X on the broader civil rights struggle.', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can describe Johnson''s role in passing the Civil Rights Act and Voting Rights Act.', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can analyse Johnson''s motivations for supporting civil rights legislation.', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can evaluate Johnson''s overall significance for the civil rights movement.', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can describe the different approaches of the NAACP, SCLC, SNCC, and Nation of Islam.', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can compare and contrast the strategies of these key organisations.', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can analyse how these groups complemented and sometimes conflicted with each other.', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-3', 'I can evaluate which organisations were most effective and why.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-3', 'Non-violent philosophy', 'Influenced by Gandhi and Christian theology; sought to expose injustice through peaceful protest and moral persuasion. Letter from Birmingham Jail MLK''s defence of non-violent direct (1963) action and criticism of white moderates who preferred ''order'' over justice. ''I Have a Dream'' speech Iconic speech at the March on (1963) Washington calling for racial harmony and equality; became a defining moment of the movement. SCLC (Southern Christian Civil rights organisation founded by Leadership Conference) MLK in 1957; coordinated non-violent campaigns across the South. ☑', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-3', 'Malcolm X (1925--1965)', 'Influential African American activist; advocate of Black empowerment and self-defence; initially a Nation of Islam minister.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-3', 'Nation of Islam', 'Religious organisation advocating Black separatism, self-reliance, and pride; Malcolm X was its most prominent spokesperson.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-3', '''By any means necessary''', 'Malcolm X''s assertion that African Americans should defend themselves against racial violence; contrasted with MLK''s non-violence. Malcolm X''s pilgrimage to After leaving the Nation of Islam, his Mecca (1964) hajj experience led him to embrace a more inclusive vision of racial justice.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-3', 'Assassination (Feb 1965)', 'Malcolm X was assassinated by Nation of Islam members; his autobiography became hugely influential. ☑', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-3', 'Johnson''s political skill', 'Master of legislative manoeuvring; used persuasion, deal-making, and Kennedy''s legacy to overcome Southern Democratic opposition. ☑', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-3', 'NAACP', 'Oldest civil rights organisation (founded 1909); focused on legal challenges to segregation; key role in Brown v. Board.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-3', 'SCLC', 'Founded 1957 by MLK; coordinated non-violent campaigns; church-based leadership in the South. SNCC (Student Non-violent Student-led organisation; organised Coordinating Committee) sit-ins, Freedom Rides, voter registration; became more radical by mid-1960s. Nation of Islam (Black Religious movement advocating Black Muslims) separatism and self-reliance; Malcolm X was its most prominent spokesperson.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-3', 'Sit-in movement (1960)', 'Student-led sit-ins at segregated lunch counters, beginning in Greensboro, NC; spread to over 70 cities. ☑', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can distinguish between ''Petty Apartheid'' and ''Grand Apartheid''.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can describe key apartheid legislation and its impact.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can explain the Population Registration Act and Group Areas Act.', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can analyse how apartheid created a comprehensive system of racial control.', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can describe the Bantustan/homeland system and its purposes.', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can explain the significance of forced removals like Sophiatown.', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can analyse the impact of pass laws on Black South Africans.', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can discuss the Bantu Education Act and its long-term consequences.', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can evaluate how classification and segregation maintained white power.', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can describe the Defiance Campaign and its results.', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can explain the significance of the Freedom Charter.', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can analyse the Women''s March of 1956 and its importance.', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can discuss the Treason Trial and its impact on the movement.', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can evaluate the effectiveness of non-violent resistance against apartheid.', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can describe the events of the Sharpeville Massacre.', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can explain why Sharpeville was a turning point in the anti-apartheid struggle.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can analyse the decision to form MK and adopt armed struggle.', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can evaluate whether the turn to violence was justified and effective.', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can describe Mandela''s role in the ANC and MK.', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can explain the significance of the Rivonia Trial.', 20);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can analyse the impact of Mandela''s imprisonment on the anti-apartheid movement.', 21);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can evaluate Mandela''s significance as a symbol of resistance.', 22);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can describe the contributions of Luthuli, Sobukwe, and Tutu to the anti-apartheid movement.', 23);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can compare different approaches within the anti-apartheid movement.', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-4', 'I can evaluate the relative significance of key individuals.', 25);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Apartheid', 'System of institutionalised racial segregation in South Africa (1948--1994); enforced white minority rule over the Black majority. National Party victory Afrikaner-dominated party won the (1948) election on a platform of apartheid; began systematic racial legislation.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Petty Apartheid', 'Laws enforcing everyday segregation: separate facilities (beaches, buses, benches, hospitals) for different racial groups.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Grand Apartheid', 'Large-scale structural segregation: homeland (Bantustan) system, population registration, forced removals. Population Registration Act Classified all South Africans into (1950) racial categories: White, Black, Coloured, Indian; determined every aspect of life.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Group Areas Act (1950)', 'Designated specific areas for each racial group; forced millions of non-white people to relocate to designated areas. ☑', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Bantustans (Homelands)', 'Designated territories for Black South Africans; intended to strip them of South African citizenship; overcrowded and underdeveloped.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Sophiatown removal (1955)', 'Forced removal of Black residents from Sophiatown, a vibrant multiracial suburb of Johannesburg, to Meadowlands (Soweto).', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Pass Laws', 'Required Black South Africans to carry ''pass books'' at all times; controlled movement and restricted access to white areas.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Bantu Education Act (1953)', 'Established separate, inferior education for Black South Africans; designed to prepare them only for manual labour. Reservation of Separate Legalised segregation of all public Amenities Act (1953) facilities; explicitly stated that facilities did not need to be equal. ☑', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Defiance Campaign (1952)', 'ANC-led campaign of non-violent civil disobedience against apartheid laws; 8,500 arrested; membership grew from 20,000 to 100,000.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Freedom Charter (1955)', 'Adopted at the Congress of the People; declared South Africa belongs to all who live in it; vision for a non-racial democratic South Africa. Congress of the People Multi-racial gathering at Kliptown that (1955) adopted the Freedom Charter; included ANC, Indian Congress, Coloured People''s Congress.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Women''s March (1956)', '20,000 women of all races marched to the Union Buildings in Pretoria to protest the extension of pass laws to women.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Treason Trial (1956--61)', '156 anti-apartheid activists (including Mandela) charged with treason; all eventually acquitted; demonstrated government repression. ☑', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'State of Emergency (1960)', 'Government declared after Sharpeville; ANC and PAC were banned; thousands arrested.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Umkhonto we Sizwe (MK)', 'Armed wing of the ANC (''Spear of the Nation''), founded 1961; began sabotage campaign against government infrastructure.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Turn to armed struggle', 'After Sharpeville and the banning of the ANC, Mandela and others concluded that non-violence alone could not defeat apartheid. ☑', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Nelson Mandela (1918--2013)', 'ANC leader; co-founded MK; imprisoned 1964--1990; first democratically elected president of South Africa (1994).', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Rivonia Trial (1963--64)', 'Trial of MK leaders including Mandela; charged with sabotage and conspiracy; Mandela sentenced to life imprisonment. Mandela''s speech from the Powerful courtroom speech declaring his dock commitment to a democratic, free society and his willingness to die for this ideal.', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Robben Island', 'Prison island where Mandela and other political prisoners were held; became a symbol of the anti-apartheid struggle.', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Impact of Rivonia', 'Decapitated the ANC leadership inside South Africa; but Mandela became an international symbol of resistance. ☑', 19);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Albert Luthuli', 'ANC President (1952--1967); advocate of non-violent resistance; first African Nobel Peace Prize laureate (1960).', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Robert Sobukwe', 'Founder and leader of the PAC; organised the anti-pass campaign that led to Sharpeville; imprisoned and then placed under house arrest.', 21);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Desmond Tutu', 'Anglican Archbishop; anti-apartheid campaigner who advocated for non-violent resistance and international sanctions; Nobel Peace Prize (1984).', 22);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-4', 'Oliver Tambo', 'ANC leader who led the organisation in exile after the bannings; maintained international pressure on the apartheid government. ☑', 23);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can explain how Meiji-era modernisation laid the groundwork for Japanese militarism.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can describe the influence of Bushido and emperor worship on foreign policy.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can explain the role of the Kwantung Army in driving expansionist policy.', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can discuss how Pan-Asianism was used to justify Japanese expansion.', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can analyse the impact of the Cardinal Principles (1937) on ultra-nationalism.', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can evaluate the extent to which the military influenced government policy by the 1930s.', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can explain the decline of Taisho Democracy and the rise of military influence.', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can describe the role of the Zaibatsu in Japan''s political economy.', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can analyse how the Great Depression intensified support for expansionism.', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can discuss the significance of the 15 May 1932 and 26 February 1936 incidents.', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can evaluate the impact of the rural-urban divide on political radicalisation.', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can link domestic economic issues to the adoption of aggressive foreign policy.', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can describe the political fragmentation of China in the early 20th century.', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can explain the GMD-CCP rivalry and its impact on China''s resistance to Japan.', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can analyse Chiang Kai-shek''s policy of prioritising internal enemies over Japan.', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can describe the Xi''an Incident and its significance for the Second United Front.', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can evaluate the extent to which Chinese weakness enabled Japanese expansion.', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can describe the Mukden Incident and explain how it was a false-flag operation.', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can explain the establishment and nature of Manchukuo as a puppet state.', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can analyse the strategic and economic reasons for invading Manchuria.', 20);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can describe the Tanggu Truce and its implications.', 21);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can evaluate the international response to the Manchurian invasion.', 22);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can describe the Marco Polo Bridge Incident and its significance.', 23);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can explain the course of the Sino-Japanese War from 1937 to 1941.', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can discuss the Rape of Nanjing and its significance.', 25);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can analyse the effectiveness of the Second United Front.', 26);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can evaluate why the war reached a stalemate by 1938.', 27);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can explain the significance of the Tripartite Pact and Anti-Comintern Pact.', 28);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can describe the Greater East Asia Co-Prosperity Sphere and its purposes.', 29);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can trace the escalation of US-Japan tensions from 1940 to 1941.', 30);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can analyse the decision-making behind the Pearl Harbor attack.', 31);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-1', 'I can evaluate whether Pearl Harbor was an act of desperation or calculated strategy.', 32);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Meiji Restoration (1868)', 'Modernisation of Japan; adoption of Western military technology and imperial ambitions; foundation for future expansionism.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Bushido', 'The warrior code of honour that underpinned Japanese military culture and justified sacrifice for the emperor and the nation.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Emperor worship (kokutai)', 'The belief in the divinity of the Emperor, used to rally national unity and justify imperial expansion as a sacred duty.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Kwantung Army', 'The Japanese military force stationed in Manchuria that acted independently and engineered the Mukden Incident in 1931.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Pan-Asianism', 'Ideology promoting Japanese leadership of Asia against Western imperialism; used to justify the Greater East Asia Co-Prosperity Sphere. Cardinal Principles of the Ministry of Education publication National Entity (Kokutai no asserting the Emperor''s divinity and Hongi, 1937) promoting self-sacrifice for the nation; fuelled ultra-nationalism. ☑', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Zaibatsu', 'Powerful Japanese industrial and financial conglomerates (e.g. Mitsui, Mitsubishi) that influenced government policy and benefited from military expansion. Great Depression impact on Collapse of silk exports, mass rural Japan poverty, bank failures (1927 crisis: 25% of banks collapsed); fuelled support for military expansion.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', '15 May Incident (1932)', 'Assassination of PM Inukai Tsuyoshi by ultra-nationalist naval officers; effectively ended party government in Japan.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', '26 February Incident (1936)', 'Attempted military coup by young army officers; though it failed, it demonstrated military power over civilian politics.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Rural-urban divide', 'Rural populations, suffering most from economic hardship, were more conservative and nationalistic; many enlisted in the army, supporting expansionism. ☑', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Warlord Era (1916--1928)', 'Period following the fall of the Qing Dynasty when regional military leaders controlled different parts of China, creating political fragmentation.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Guomindang (GMD/KMT)', 'Chinese Nationalist Party led by Chiang Kai-shek (Jiang Jieshi); sought to unify China but faced communist insurgency and Japanese aggression. Chinese Communist Party Founded 1921; led by Mao Zedong from (CCP) 1935; rival to the GMD, fighting a civil war that weakened China''s ability to resist Japan.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Chinese Civil War', 'Conflict between the GMD and CCP that diverted Chinese resources from resisting Japanese expansion and created political instability exploited by Japan.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Chiang Kai-shek''s strategy', 'Prioritised fighting the CCP over resisting Japan (''first internal pacification, then external resistance''), which enabled Japanese expansion.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Xi''an Incident (1936)', 'Kidnapping of Chiang Kai-shek by Zhang Xueliang, forcing a temporary GMD-CCP alliance (Second United Front) against Japan. ☑', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Manchukuo (1932)', 'Japanese puppet state established in Manchuria; nominally led by Puyi, the last Qing emperor, but controlled by Japan.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'South Manchuria Railway', 'Japanese-controlled railway whose ''sabotage'' was used as justification for the Manchurian invasion.', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Tanggu Truce (1933)', 'Agreement creating a demilitarised zone south of the Great Wall; effectively recognised Japanese control of Manchuria. Strategic importance of Rich in coal, iron, and agricultural Manchuria resources; seen as vital for Japanese economic self-sufficiency and as a buffer against the Soviet Union. ☑', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Rape of Nanjing (Dec 1937)', 'Massacre of an estimated 200,000--300,000 Chinese civilians and POWs by Japanese forces after capturing the Chinese capital.', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Second United Front (1937)', 'Uneasy alliance between the GMD and CCP to resist Japanese invasion, following the Xi''an Incident. Japanese ''Three Alls'' ''Kill all, burn all, loot all'' -- Policy scorched earth strategy used against Chinese resistance, particularly in rural areas. Chongqing as wartime After Nanjing fell, the GMD relocated capital its capital to Chongqing in southwest China, continuing resistance.', 19);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Stalemate (1938--1941)', 'After initial rapid advances, the war reached a stalemate as China traded space for time and Japan struggled to control vast territory. ☑', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Tripartite Pact (Sept 1940)', 'Alliance between Germany, Italy, and Japan; each recognised the other''s sphere of influence and agreed mutual assistance.', 21);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Anti-Comintern Pact (1936)', 'Agreement between Japan and Germany (Italy joined 1937) opposing the Communist International; precursor to the Tripartite Pact. Greater East Asia Japanese concept of an Asia-Pacific Co-Prosperity Sphere bloc free from Western imperialism, under Japanese leadership; used to justify expansion. Japanese occupation of Japan moved into French Indochina, Indochina (1940--41) triggering US oil embargo and asset freezing -- critical steps toward Pearl Harbor.', 22);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'Pearl Harbor (7 Dec 1941)', 'Surprise Japanese attack on the US naval base in Hawaii; brought the US into WWII and transformed the conflict into a global war.', 23);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1', 'US oil embargo (1941)', 'After Japan occupied southern Indochina, the US froze Japanese assets and imposed a total trade embargo, cutting 80% of Japan''s oil supply. ☑', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2', 'I can describe the Lytton Commission and its findings.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2', 'I can explain why Japan rejected the Lytton Report and left the League.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2', 'I can analyse the significance of the Manchurian crisis for collective security.', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2', 'I can evaluate the League of Nations'' effectiveness in responding to Japanese aggression.', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2', 'I can explain how and why the Second United Front was formed.', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2', 'I can analyse the effectiveness of the United Front in resisting Japan.', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2', 'I can discuss the internal tensions between the GMD and CCP within the Front.', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2', 'I can evaluate why the United Front ultimately failed.', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2', 'I can describe the Stimson Doctrine and its limitations.', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2', 'I can explain the significance of Roosevelt''s Quarantine Speech.', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2', 'I can trace the escalation of US-Japan tensions from 1937 to 1941.', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2', 'I can analyse the impact of the US oil embargo on Japanese decision-making.', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2', 'I can evaluate whether the Hull Note made war between the US and Japan inevitable.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2', 'Lytton Commission (1932)', 'League of Nations investigation into the Manchurian crisis; concluded Japan had acted aggressively but proposed a compromise.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2', 'Lytton Report findings', 'Acknowledged Japanese interests in Manchuria but concluded the invasion was not justified; recommended Manchuria become an autonomous region under Chinese sovereignty. Japan''s withdrawal from Japan left the League of Nations after League (1933) the Assembly adopted the Lytton Report, demonstrating the League''s inability to enforce its decisions. Failure of collective The Manchurian crisis demonstrated that security the League could not prevent aggression by a major power, setting a precedent for future failures. ☑', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2', 'Stimson Doctrine (1932)', 'US policy of non-recognition of territorial changes achieved by force; applied to Manchukuo but had no enforcement mechanism. Quarantine Speech (Oct Roosevelt''s speech calling for the 1937) ''quarantine'' of aggressor nations; signalled a shift from isolationism but produced no immediate action.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2', 'Panay Incident (Dec 1937)', 'Japanese aircraft sank the USS Panay on the Yangtze River; Japan apologised, but it increased American suspicion.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2', 'Hull Note (Nov 1941)', 'US demands that Japan withdraw from China and Indochina; seen by Japan as an ultimatum that made war inevitable. US asset freeze and oil After Japan occupied southern embargo (July 1941) Indochina, the US froze Japanese assets and cut off oil supplies, threatening Japan''s ability to wage war.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2', 'Lend-Lease to China (1941)', 'US provided military aid to China under the Lend-Lease programme, further straining US-Japan relations. ☑', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can explain Hitler''s key foreign policy objectives and their ideological basis.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can describe Mussolini''s aims for Italian expansion and great power status.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can compare and contrast the foreign policy ideologies of Fascist Italy and Nazi Germany.', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can analyse how ideology shaped actual foreign policy decisions.', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can evaluate the extent to which Hitler''s foreign policy was a coherent plan vs. opportunism.', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can explain how autarky drove both German and Italian expansionism.', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can describe the Four-Year Plan and its connection to war preparation.', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can analyse the role of rearmament in the German economic recovery.', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can discuss how Italian economic failures contributed to imperial ambitions.', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can evaluate the relationship between economic policy and foreign policy aggression.', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can explain the policy of appeasement and its main justifications.', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can describe the changing diplomatic alignments of the 1930s (Stresa Front, Rome-Berlin Axis).', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can analyse the collapse of collective security through specific events.', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can evaluate the strengths and weaknesses of appeasement as a policy.', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can discuss how diplomatic realignments enabled German and Italian expansion.', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can list and explain Germany''s key challenges to the post-war settlements (1933--38).', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can describe the remilitarisation of the Rhineland and explain why it was a turning point.', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can analyse the Anschluss with Austria and international responses.', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can explain the Sudetenland crisis and the Munich Agreement.', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can evaluate whether Hitler''s actions were planned or opportunistic.', 20);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can describe the Italian invasion of Abyssinia and its causes.', 21);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can explain the League of Nations'' response and why sanctions failed.', 22);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can analyse the impact of the Abyssinian crisis on international relations.', 23);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can describe Italy''s annexation of Albania and entry into WWII.', 24);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can evaluate how effective Italian expansion was in achieving Mussolini''s aims.', 25);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can explain the significance of Germany''s invasion of Czechoslovakia in March 1939.', 26);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can describe the Nazi-Soviet Pact and its secret protocols.', 27);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can analyse why Britain and France declared war over Poland but not Czechoslovakia.', 28);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can evaluate the significance of the Nazi-Soviet Pact for the outbreak of war.', 29);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-3', 'I can discuss the Danzig crisis and Polish resistance to German demands.', 30);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Lebensraum', 'Nazi concept of ''living space''; justified German territorial expansion eastward into Poland and the USSR. Mussolini''s foreign policy Restore Roman greatness (spazio aims vitale), create an Italian Mediterranean empire, establish Italy as a great power (Mare Nostrum). Spazio vitale / Mare Italian equivalents of Lebensraum; Nostrum ''vital space'' and ''Our Sea'' -- Mussolini''s vision of Italian dominance in the Mediterranean.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Mein Kampf (1925)', 'Hitler''s autobiography outlining his ideological worldview, including anti-Semitism, Lebensraum, and opposition to Versailles. Hitler''s views on the Treaty Saw it as a ''diktat'' and national of Versailles humiliation; reversal of its terms was central to Nazi foreign policy. ☑', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Autarky', 'Policy of economic self-sufficiency pursued by both Germany and Italy; used to justify territorial expansion for resources.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'German rearmament', 'Massive military build-up from 1933; violated Versailles but stimulated the economy and prepared for expansionism.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Four-Year Plan (1936)', 'Goring''s plan to prepare Germany''s economy for war within four years; focused on autarky and rearmament. Battle for Grain / Battle for Mussolini''s campaigns for agricultural Land (Italy) self-sufficiency; failures contributed to desire for colonial expansion.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Mefo Bills', 'Secret financial instruments used to fund German rearmament without appearing in the budget; created by Hjalmar Schacht.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Italian corporatism', 'Mussolini''s economic system mixing capitalist and socialist elements; aimed at self-sufficiency but fell short, driving imperial ambitions. ☑', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Appeasement', 'British and French policy of making concessions to dictators to avoid war; most associated with Neville Chamberlain and the Munich Agreement.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Stresa Front (1935)', 'Agreement between Britain, France, and Italy to oppose German violations of Versailles; collapsed over Abyssinian crisis.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Rome-Berlin Axis (Oct 1936)', 'Alliance between Mussolini and Hitler; solidified after the Abyssinian crisis pushed Italy away from Britain and France.', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Anti-Comintern Pact (1936)', 'Agreement between Germany and Japan (Italy joined 1937) against communist expansion; foundation of the Axis alliance. Anglo-German Naval Agreement Britain allowed Germany to build a navy (1935) 35% the size of the Royal Navy; violated Versailles without French consultation.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Hoare-Laval Pact (1935)', 'Secret British-French plan to give most of Abyssinia to Italy; leaked and caused public outrage, discrediting appeasement. ☑', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Sudetenland crisis (1938)', 'Hitler demanded the Sudetenland (German-speaking area of Czechoslovakia); resolved at Munich when Britain and France agreed to cession. Munich Agreement (Sept Britain, France, Germany, and Italy 1938) agreed to cede the Sudetenland to Germany; Chamberlain declared ''peace for our time''. ☑', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Battle of Adwa (1896)', 'Humiliating Italian defeat by Ethiopia that Mussolini sought to avenge; shaped Italian imperial ambitions. League of Nations sanctions Economic sanctions imposed after the on Italy Abyssinian invasion; excluded oil and were largely ineffective; Suez Canal remained open. Italian annexation of Albania Italy invaded Albania to match German (April 1939) expansion and secure a strategic position in the Balkans. Italy''s entry into WWII Mussolini declared war on France and (June 1940) Britain after Germany''s successful invasion of France, hoping for easy territorial gains.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Pact of Steel (May 1939)', 'Military alliance between Germany and Italy; committed both to support each other in war. ☑', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-3', 'Danzig crisis (1939)', 'Hitler demanded the return of Danzig (Gdansk) and a corridor through Polish territory; Poland refused with British support. ☑', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can explain the different reasons for British appeasement.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can describe France''s defensive strategy and its limitations.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can analyse the failure of collective security against German aggression.', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can discuss Soviet attempts to form anti-German alliances and why they failed.', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can evaluate whether a stronger response could have prevented war.', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can describe the international response to Italy''s invasion of Abyssinia.', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can explain why League of Nations sanctions were ineffective.', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can analyse the significance of the Hoare-Laval Pact.', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can evaluate the impact of the Abyssinian crisis on the Stresa Front.', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can describe the Fall of France and its impact on the war.', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can explain the significance of the Battle of Britain.', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can analyse Churchill''s role in shaping British war policy.', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can discuss US support through Lend-Lease and its significance.', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-4', 'I can evaluate the consequences of Italian military failures for the Axis.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-4', 'French defensive strategy', 'France relied on the Maginot Line and alliances; internal political divisions weakened resolve to confront Germany.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-4', 'Maginot Line', 'French defensive fortification along the German border; symbolised France''s defensive mentality and inability to project power. Soviet attempts at collective USSR sought alliances with France and security Britain against Germany; mutual distrust prevented effective cooperation.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-4', 'Franco-Soviet Pact (1935)', 'Mutual assistance pact between France and the USSR; never effectively implemented due to mutual suspicion and lack of military planning. ☑', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-4', 'Hoare-Laval Pact (Dec 1935)', 'Secret plan by Britain and France to give two-thirds of Abyssinia to Italy; leaked, caused scandal, discredited appeasement.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-4', 'League sanctions on Italy', 'Limited economic sanctions imposed Nov 1935; excluded oil, coal, and steel; ineffective in stopping the invasion.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-4', 'Suez Canal issue', 'Britain controlled the Suez Canal but did not close it to Italian shipping, allowing supply of Italian forces in East Africa.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-4', 'Collapse of Stresa Front', 'The Abyssinian crisis and Western sanctions pushed Italy away from Britain and France towards alliance with Germany. ☑', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-4', 'Fall of France (June 1940)', 'Germany''s rapid defeat of France left Britain fighting alone against Germany and Italy in Western Europe.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-4', 'Battle of Britain (1940)', 'German air campaign to achieve air superiority over Britain; failure prevented a German invasion (Operation Sea Lion).', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-4', 'Churchill''s leadership', 'Replaced Chamberlain as PM in May 1940; rallied British resistance with defiant speeches and refusal to negotiate with Hitler. US Lend-Lease Act (March US provided military aid to Britain and 1941) its allies; crucial for sustaining the war effort before full US entry. Italian failures in North Italian military defeats required Africa and Greece (1940--41) German intervention, overextending Axis resources. ☑', 10);
